// // This module converts a 4-bit binary number to its two's complement representation. It inverts the bits and adds one for negative numbers.
module top_module(
    input [3:0] iNum,
    output reg [3:0] oNum
);always @(*) begin
    if(iNum[3] == 1) begin
        oNum = ~(iNum) + 1;
    end
    else begin
        oNum = iNum;
    end
end

endmodule
